func solve(edges [][]int64, online []bool, k int64) int64 {
	n := len(online)
	if n == 0 {
		return -1
	}

	// Step 1: Topological sort
	topOrder := topologicalSort(n, edges)

	// Step 2: Find max edge cost
	maxEdge := int64(0)
	for _, e := range edges {
		if e[2] > maxEdge {
			maxEdge = e[2]
		}
	}

	// Step 3: Binary search
	low := int64(0)
	high := maxEdge
	ans := int64(-1)

	for low <= high {
		mid := (low + high) / 2
		if canReach(mid, topOrder, online, edges, k, n) {
			ans = mid
			low = mid + 1
		} else {
			high = mid - 1
		}
	}

	return ans
}

func topologicalSort(n int, edges [][]int64) []int {
	adj := make([][]int, n)
	inDegree := make([]int, n)
	for _, e := range edges {
		u := int(e[0])
		v := int(e[1])
		adj[u] = append(adj[u], v)
		inDegree[v]++
	}

	queue := []int{}
	for i := 0; i < n; i++ {
		if inDegree[i] == 0 {
			queue = append(queue, i)
		}
	}

	topOrder := []int{}
	for len(queue) > 0 {
		u := queue[0]
		queue = queue[1:]
		topOrder = append(topOrder, u)
		for _, v := range adj[u] {
			inDegree[v]--
			if inDegree[v] == 0 {
				queue = append(queue, v)
			}
		}
	}

	return topOrder
}

func canReach(mid int64, topOrder []int, online []bool, edges [][]int64, k int64, n int) bool {
	// Build the subgraph edges
	var subEdges [][]int64
	for _, e := range edges {
		u := int(e[0])
		v := int(e[1])
		cost := e[2]
		if cost >= mid && online[u] && online[v] {
			subEdges = append(subEdges, []int64{int64(u), int64(v), cost})
		}
	}

	// DP to find minimal sum
	dist := make([]int64, n)
	for i := 0; i < n; i++ {
		dist[i] = math.MaxInt64
	}
	dist[0] = 0

	for _, u := range topOrder {
		if dist[u] == math.MaxInt64 {
			continue
		}
		// Iterate through all edges in subEdges that start from u
		for _, e := range subEdges {
			if e[0] != int64(u) {
				continue
			}
			v := int(e[1])
			cost := e[2]
			if dist[u]+cost < dist[v] {
				dist[v] = dist[u] + cost
			}
		}
	}

	if dist[n-1] <= k {
		return true
	}
	return false
}
